import { Injectable, signal } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class ThemeService {
  private readonly KEY = 'am_portfolio_theme';
  theme = signal<'dark' | 'light'>('dark');

  init() {
    let saved = null as string | null;
    try { saved = localStorage.getItem(this.KEY); } catch { /* ignore */ }
    if (!saved && window.matchMedia?.('(prefers-color-scheme: light)').matches) {
      saved = 'light';
    }
    this.apply((saved as 'dark' | 'light') || 'dark');
    window.matchMedia?.('(prefers-color-scheme: dark)').addEventListener('change', e => {
      try { if (!localStorage.getItem(this.KEY)) this.apply(e.matches ? 'dark' : 'light'); } catch { /* ignore */ }
    });
  }

  toggle() {
    this.apply(this.theme() === 'dark' ? 'light' : 'dark');
  }

  private apply(t: 'dark' | 'light') {
    this.theme.set(t);
    document.documentElement.classList.toggle('dark', t === 'dark');
    document.documentElement.classList.toggle('light-theme', t === 'light');
    try { localStorage.setItem(this.KEY, t); } catch { /* ignore */ }
  }
}
